solution_code:
#include <iostream>

int scale(int x) {
    return x * 2;
}

double scale(double x) {
    return x * 2.0;
}

int main() {
    int n;
    double d;
    std::cin >> n >> d;
    std::cout << "Scaled int: " << scale(n) << "\n";
    std::cout << "Scaled double: " << scale(d) << "\n";
    return 0;
}

