solution_code:
#include <iostream>
#include <string>
#include <sstream>

std::string formatLabel(int code) {
    return "Code: " + std::to_string(code);
}

std::string formatLabel(double val) {
    std::ostringstream oss;
    oss << val;
    return "Value: " + oss.str();
}

int main() {
    int c;
    double v;
    std::cin >> c >> v;
    std::cout << formatLabel(c) << "\n";
    std::cout << formatLabel(v) << "\n";
    return 0;
}
